  malphite: { diff: "MIRROR", tone: "#e8b84b", tldr: "Armor mirror \u2014 whoever wins the Q-poke and E-slow war wins.", breakdown: "Pure Malphite mirror: it\u2019s a Q-poke and armor-stacking race. Whoever out-pokes and engages first wins.", dos: ["Win the Q-poke war", "E-slow his autos", "Engage R first"], donts: ["Eat his R knockup", "Auto into his W", "Fall behind in armor"], key: { slot: "R", name: "Unstoppable Force", cd: "130s", note: "Whoever lands R first wins the all-in.", winT: "ULT DOWN", winS: "R-W-E him." }, hold: "Hold R to bait his \u2014 whoever lands the R-engage first wins; E-slow to win the auto trades.", tip: "It\u2019s a Q-poke and armor mirror \u2014 win the poke war, E-slow his autos, and land R first.", win: "Win the poke war and R first." },
