  shen: { diff: "EVEN", tone: "#e8b84b", tldr: "Dodge his taunt \u2014 E-slow his autos, Q-poke him.", breakdown: "Dodge his E taunt, E-slow his attack speed, Q-poke, and out-trade his weak 1v1.", dos: ["Dodge his E taunt", "E-slow his attack speed", "Track his R roams"], donts: ["Get taunted into his W", "Fight his W block", "Ignore his R"], key: { slot: "E", name: "Shadow Dash (Taunt)", cd: "18s", note: "His engage CC. Dodge it.", winT: "TAUNT DOWN", winS: "R-W-E him." }, hold: "Hold E to slow his autos and Q to poke \u2014 dodge his taunt and out-trade his 1v1.", tip: "Dodge his taunt, E-slow his autos, and Q-poke \u2014 out-trade his weak 1v1; ping his R roams.", win: "Dodge his taunt and out-trade him." },
