  // ===== OFF-META & FLEX PICKS =====
  akshan: {"diff":"TRICKY","tone":"#ff8b3d","tldr":"Weather the poke — Q-poke him down and hold R for the game-winning engage.","breakdown":"Akshan plays around Heroic Swing. Q steals move speed on his step-ups, E guts his attack speed if he commits, and your R wins fights — lane is just a bank for it. Doran’s Shield blunts the poke war.","dos":["Q-poke his step-ups","E his attack speed when he commits","Save R for the pick / teamfight"],"donts":["Trade into his Heroic Swing","Waste R on chip","Forget your passive shield resets"],"key":{"slot":"E","name":"Heroic Swing","cd":"14s","note":"His dash + camera swing escape. Engage when it's down.","winT":"SWING DOWN","winS":"Q-poke, R the pick."},"win":"Q-poke him down and hold R for the game-winning engage."},
  cassiopeia: {"diff":"HARD","tone":"#ff5d6c","tldr":"He kites you out — survive, then Q-poke him down and hold R for the game-winning engage.","breakdown":"Cassiopeia plays around Miasma. Q steals move speed on his step-ups, E guts his attack speed if he commits, and your R wins fights — lane is just a bank for it. Take Mercs / MR shard — his damage is magic. Doran’s Shield blunts the poke war.","dos":["Q-poke his step-ups","E his attack speed when he commits","Save R for the pick / teamfight"],"donts":["Trade into his Miasma","Waste R on chip","Forget your passive shield resets"],"key":{"slot":"W","name":"Miasma","cd":"12s","note":"Grounds you — dashes and movement abilities are disabled inside it.","winT":"MIASMA DOWN","winS":"Q-poke, R the pick."},"win":"Q-poke him down and hold R for the game-winning engage."},
